    private async Task LoadSaleForEdit()
    {
        try
        {
            var cdkey = CompanyService.SelectedCompany?.LicenceKey ?? string.Empty;
            var companyCode = CompanyService.SelectedCompany?.CompanyCode ?? string.Empty;
            var url = $"{ApiConstants.BaseUrl}/api/Order/sales/{InvId}";
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("CdyKey", cdkey);
            request.Headers.Add("CompanyCode", companyCode);
            var response = await Http.SendAsync(request);
            if (response.IsSuccessStatusCode)
            {
                var json = await response.Content.ReadAsStringAsync();
                var sale = System.Text.Json.JsonSerializer.Deserialize<SaleRecord>(json, new System.Text.Json.JsonSerializerOptions { PropertyNameCaseInsensitive = true });
                if (sale != null)
                {
                    Sale = sale;
                }
            }
        }
        catch { }
    }

    private async Task InitializeData()
    {
        // Load customers from API
        var apiCustomers = await SalesDropdownService.GetCustomersAsync("");
        AllCustomers = apiCustomers.Select(c => new CustomerRecord
        {
            Name = c.Name,
            Phone = c.Mobile,
            Address = c.Address,
            GSTIN = c.GSTIN,
            LedgerId = (int)c.LID,
            Balance = c.Balance
        }).ToList();

        // Load dropdowns from API
        PriceLists = await SalesDropdownService.GetPriceListsAsync();
        CostCentres = await SalesDropdownService.GetCostCentresAsync();
        Salesmen = await SalesDropdownService.GetSalesmenAsync();
        Agents = await SalesDropdownService.GetAgentsAsync();

        await FetchNewInvIdAsync("SALES","Sales");

        FilteredItems = AllItems;
        FilteredCustomers = AllCustomers;
        Sale.Date = DateTime.Now;
        StateHasChanged();
    }

    private async Task FetchNewInvIdAsync(string SALES, string Sales)
    {
        try
        {
            // Get company details from selected company
            var cdkey = CompanyService.SelectedCompany?.LicenceKey ?? string.Empty;
            var companyCode = CompanyService.SelectedCompany?.CompanyCode ?? string.Empty;
            var url = $"http://localhost:5090/api/Order/last-invid?vchrType={Uri.EscapeDataString(SALES)}&nodeName={Uri.EscapeDataString(Sales)}";
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("CdyKey", cdkey);
            request.Headers.Add("CompanyCode", companyCode);

            // Add Bearer token to Authorization header
            var token = await TokenService.GetTokenAsync();
            if (!string.IsNullOrWhiteSpace(token))
            {
                request.Headers.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", token);
            }

            var lastInvIdResponse = await Http.SendAsync(request);
            if (lastInvIdResponse.IsSuccessStatusCode)
            {
                var lastInvIdString = await lastInvIdResponse.Content.ReadAsStringAsync();
                if (double.TryParse(lastInvIdString, out var lastInvId))
                {
                    newInvId = lastInvId + 1;
                }
                else
                {
                    newInvId = 1;
                }
            }
            else
            {
                newInvId = 1;
            }
        }
        catch
        {
            newInvId = 1;
        }
    }

    private async Task OpenItemModal()
    {
        ShowItemModal = true;
        ItemSearchQuery = "";
        try
        {
            var cdkey = CompanyService.SelectedCompany?.LicenceKey ?? string.Empty;
            var companyCode = CompanyService.SelectedCompany?.CompanyCode ?? string.Empty;
            var request = new HttpRequestMessage(HttpMethod.Get, $"{ApiConstants.BaseUrl}/api/Order/items");
            request.Headers.Add("CdyKey", cdkey);
            request.Headers.Add("CompanyCode", companyCode);

            var response = await Http.SendAsync(request);
            if (response.IsSuccessStatusCode)
            {
                var json = await response.Content.ReadAsStringAsync();
                var items = System.Text.Json.JsonSerializer.Deserialize<List<SalesItem>>(json, new System.Text.Json.JsonSerializerOptions { PropertyNameCaseInsensitive = true });
                AllItems = items ?? new List<SalesItem>();
                foreach (var item in AllItems)                {
                    if (item.Rate == 0.00m)
                    {
                        item.Rate = item.MRP;
                    }
                }
                FilteredItems = AllItems;
            }
            else
            {
                AllItems = new List<SalesItem>();
                FilteredItems = AllItems;
            }
        }
        catch
        {
            AllItems = new List<SalesItem>();
            FilteredItems = AllItems;
        }
    }

    private async Task AddItemAsync(SalesItem item)
    {
        string batchUnique = string.Empty;
        try
        {
            var url = $"{ApiConstants.BaseUrl}/api/Order/GetBatchByItemId/{item.ItemId}";
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            var cdkey = CompanyService.SelectedCompany?.LicenceKey ?? string.Empty;
            var companyCode = CompanyService.SelectedCompany?.CompanyCode ?? string.Empty;
            request.Headers.Add("CdyKey", cdkey);
            request.Headers.Add("CompanyCode", companyCode);
            var response = await Http.SendAsync(request);
            if (response.IsSuccessStatusCode)
            {
                var json = await response.Content.ReadAsStringAsync();
                Console.WriteLine($"BatchUnique API response: {json}");
                // Assuming API returns a single object with BatchUnique property
                var stock = System.Text.Json.JsonSerializer.Deserialize<BatchUniqueModel>(json, new System.Text.Json.JsonSerializerOptions { PropertyNameCaseInsensitive = true });
                if (stock != null && !string.IsNullOrEmpty(stock.BatchUnique))
                {
                    batchUnique = stock.BatchUnique;
                    Console.WriteLine($"BatchUnique value set: {batchUnique}");
                }
                else
                {
                    Console.WriteLine("BatchUnique not found in API response or is empty.");
                }
            }
        }
        catch { }
        Sale.Items.Add(new SaleItem
        {
            ItemId = item.ItemId,
            ItemCode = item.ItemCode,
            ItemName = item.ItemName,
            Rate = item.MRP,
            MRP = item.MRP,
            TaxPer = item.TaxPercent,
            Qty = 1,
            BatchUnique = batchUnique
        });
        ShowItemModal = false;
        CalculateTotals();
    }

    private void FilterItems(ChangeEventArgs e)
    {
        ItemSearchQuery = e.Value?.ToString() ?? "";
        if (string.IsNullOrEmpty(ItemSearchQuery))
        {
            FilteredItems = AllItems;
        }
        else
        {
            FilteredItems = AllItems
                .Where(x => x.ItemCode.Contains(ItemSearchQuery, StringComparison.OrdinalIgnoreCase) ||
                           x.ItemName.Contains(ItemSearchQuery, StringComparison.OrdinalIgnoreCase))
                .ToList();
        }
    }

    private void FilterCustomers(ChangeEventArgs e)
    {
        CustomerSearch = e.Value?.ToString() ?? "";
        FilteredCustomers = AllCustomers
            .Where(x => x != null &&
                ((x.Name != null && x.Name.Contains(CustomerSearch.Trim(), StringComparison.OrdinalIgnoreCase)) ||
                 (x.Phone != null && x.Phone.Contains(CustomerSearch.Trim(), StringComparison.OrdinalIgnoreCase))))
            .ToList();
    }


    private async void SelectCustomer(CustomerRecord customer)
    {
        Sale.CustomerName = customer.Name;
        Sale.MobileNumber = customer.Phone;
        ShowCustomerModal = false;

        // Example: Assume customer.Name is unique and maps to a ledger
        // In real app, you should have a LedgerId property in CustomerRecord
        var ledgers = await ReceiptVoucherService.GetCustomerLedgersAsync();
        var ledger = ledgers.FirstOrDefault(l => l.LedgerName == customer.Name);
        if (ledger != null)
        {
            var balance = await ReceiptVoucherService.GetLedgerBalanceAsync(ledger.LedgerId);
            Sale.CustomerBalance = balance;
        }
        else
        {
            Sale.CustomerBalance = 0;
        }
        StateHasChanged();
    }

